from flask import Flask, render_template, request, redirect, url_for, abort
import os
from datetime import date

app = Flask(__name__)

DATA_DIR = 'data'

# Utility functions to load data from files

def load_songs():
    songs = []
    try:
        with open(os.path.join(DATA_DIR, 'songs.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 8:
                    continue
                song_id = int(parts[0])
                title = parts[1]
                artist_id = int(parts[2])
                album_id = int(parts[3])
                genre = parts[4]
                duration = int(parts[5])
                release_date = parts[6]
                play_count = int(parts[7])
                songs.append({
                    'song_id': song_id,
                    'title': title,
                    'artist_id': artist_id,
                    'album_id': album_id,
                    'genre': genre,
                    'duration': duration,
                    'release_date': release_date,
                    'play_count': play_count
                })
    except FileNotFoundError:
        pass
    return songs


def load_artists():
    artists = []
    try:
        with open(os.path.join(DATA_DIR, 'artists.txt'), 'r', encoding='utf-8') as f:
            for line in f:
