                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 5:
                    continue
                artist_id = int(parts[0])
                name = parts[1]
                genre = parts[2]
                country = parts[3]
                formation_year = int(parts[4])
                artists.append({
                    'artist_id': artist_id,
                    'name': name,
                    'genre': genre,
                    'country': country,
                    'formation_year': formation_year
                })
    except FileNotFoundError:
        pass
    return artists


